### Describe what's wrong
Partition pruning does not consider session timezone correctly when using toStartOfDay() (or any other epoch) function as partition key.
This affects all the multi-timezone applications that use DateTime column based functions as partition key, and break validness of the query output.
### Does it reproduce on the most recent release?
Yes
### How to reproduce
Problem is reproduceable on the latest version. Was last working on this 24.3-LTS, broken on 24.8-LTS and above (didn't check interim non-LTS versions).
[fiddle.clickhouse.com/9b578911-b237-4381-8c76-1164f9a4bd65](https://fiddle.clickhouse.com/15b88a1d-f04c-4d89-a2b0-9f3b539f31ad)
```
select '--- CH version';
select version();
select '--- setting TZ to America/New_York';
set session_timezone='America/New_York';
DROP TABLE IF EXISTS default.testpartitiondat_toStartOfDay;
CREATE TABLE default.testpartitiondat_toStartOfDay(
dtkey DateTime,
a UInt32,
b UInt32
)
ENGINE = MergeTree
PARTITION BY (toStartOfDay(dtkey))
ORDER BY tuple()
SETTINGS index_granularity = 8192;
-- load data in US tz session setting WITHOUT tz info
select '--- load data in US tz session setting WITHOUT tz info';
insert into default.testpartitiondat_toStartOfDay VALUES (toDateTime('2025-09-03 02:58:00'), 1, 1);
--- query with datetime explicitly in US TZ
select '--- query with datetime explicitly in US TZ - works';
select dtkey, _partition_value from default.testpartitiondat_toStartOfDay
where dtkey>=toDateTime('2025-09-03 00:00:00', 'America/New_York')
and dtkey<toDateTime('2025-09-03 05:00:00', 'America/New_York');
-- query without explicit TZ, relying on session tz - works
select '-- query without explicit TZ, relying on session tz - works';
select dtkey, _partition_value from default.testpartitiondat_toStartOfDay
where dtkey>=toDateTime('2025-09-03 00:00:00')
and dtkey<toDateTime('2025-09-03 05:00:00');
-- change session tz
select '-- change session tz';
set session_timezone='Europe/Bucharest';
--- query with datetime explicitly in US TZ -- fails!!!
select '--- query with datetime explicitly in US TZ -- fails!!!';
select dtkey, _partition_value from default.testpartitiondat_toStartOfDay
where dtkey>=toDateTime('2025-09-03 00:00:00', 'America/New_York')
and dtkey<toDateTime('2025-09-03 05:00:00', 'America/New_York');
-- explain plan shows that it's trying to apply pruning in server TZ, instead of using session TZ (PK works correctly)
select '-- explain plan shows that its trying to apply pruning in server TZ, instead of using session TZ (PK works correctly)';
explain indexes=1, actions=0  select dtkey, _partition_value from default.testpartitiondat_toStartOfDay
where dtkey>=toDateTime('2025-09-03 00:00:00', 'America/New_York')
